const tree = $input.first().json.tree || [];
const keep = /^(README\.md|CONTRIBUTING\.md|prompts\/qa-system\.md|domains\/.+\.md|guides\/.+\.md|plans\/.+\.md|glossary\/.+\.md)$/;
const files = tree.filter(t => t.type === 'blob' && keep.test(t.path)).sort((a, b) => a.path.localeCompare(b.path));
if (files.length === 0) throw new Error('no KB files matched');
return files.map(f => ({ json: { path: f.path, url: f.url } }));

const paths = $('Pick Files').all().map(i => i.json.path);
const blobs = $input.all();
if (paths.length !== blobs.length) throw new Error('path/blob count mismatch');
let system_prompt = 'คุณคือ Javis ผู้ช่วยคลังความรู้ของทีม ตอบจากเอกสารเท่านั้น ใช้ citations เสมอ';
const documents = [];
for (let i = 0; i < paths.length; i++) {
  const text = Buffer.from((blobs[i].json.content || '').replace(/\n/g, ''), 'base64').toString('utf8');
  if (paths[i] === 'prompts/qa-system.md') {
    const m = text.match(/```([\s\S]*?)```/);
    if (m) system_prompt = m[1].trim();
    continue;
  }
  documents.push({ type: 'document', source: { type: 'text', media_type: 'text/plain', data: text }, title: paths[i], citations: { enabled: true } });
}
documents[documents.length - 1].cache_control = { type: 'ephemeral' };
return [{ json: { system_prompt, documents } }];

const text = Buffer.from(($('Get Eval Set').first().json.content || '').replace(/\n/g, ''), 'base64').toString('utf8');
let section = null; const cases = []; let cur = null; let inTurns = false;
for (const raw of text.split('\n')) {
  const line = raw.replace(/\r$/, '');
  if (/^positive:/.test(line)) { section = 'positive'; continue; }
  if (/^negative:/.test(line)) { section = 'negative'; continue; }
  if (/^multi_turn:/.test(line)) { section = 'multi_turn'; continue; }
  if (!section || /^\s*#/.test(line)) continue;
  const mQ = line.match(/^  - q: \"(.*)\"\s*$/);
  const mT = line.match(/^  - turns:/);
  if (mQ) { cur = { type: section, q: mQ[1] }; cases.push(cur); inTurns = false; continue; }
  if (mT) { cur = { type: section, turns: [] }; cases.push(cur); inTurns = true; continue; }
  if (!cur) continue;
  const mTurn = line.match(/^      - \"(.*)\"\s*$/);
  if (inTurns && mTurn) { cur.turns.push(mTurn[1]); continue; }
  const mArr = line.match(/^    (expect_answer_contains|expect_cite): (\[.*\])\s*$/);
  if (mArr) { try { cur[mArr[1]] = JSON.parse(mArr[2]); } catch (e) {} continue; }
  if (/^    expect_no_answer: true/.test(line)) { cur.expect_no_answer = true; continue; }
  const mNote = line.match(/^    note: \"(.*)\"\s*$/);
  if (mNote) { cur.note = mNote[1]; continue; }
  const mLang = line.match(/^    lang: (\w+)/);
  if (mLang) { cur.lang = mLang[1]; continue; }
}
if (cases.length < 20) throw new Error('parsed only ' + cases.length + ' cases — parser broken?');
return cases.map((c, i) => ({ json: { idx: i, ...c, question: c.q || ('คำถามแรก: ' + (c.turns || [])[0] + '\nคำถามต่อเนื่อง: ' + (c.turns || []).slice(1).join(' / ')) } }));

const rows = $input.all(); const out = [];
for (let i = 0; i < rows.length; i++) {
  const c = $('Make Cases').itemMatching(i).json;
  const resp = rows[i].json || {};
  let answer = ''; const cites = new Set();
  for (const b of resp.content || []) if (b.type === 'text') { answer += b.text; for (const ct of b.citations || []) cites.add(ct.document_title); }
  if (!answer && resp.error) answer = '[API ERROR] ' + JSON.stringify(resp.error).slice(0, 300);
  const expect = c.type === 'negative'
    ? 'เคสนี้ KB ไม่มีข้อมูล/เป็นข้อมูลต้องห้าม บอทต้องปฏิเสธหรือบอกว่าไม่พบข้อมูล ห้ามแต่งคำตอบ' + (c.note ? (' — บริบท: ' + c.note) : '')
    : 'คำตอบต้องครอบคลุมสาระ: ' + JSON.stringify(c.expect_answer_contains || []) + ' และควรอ้างอิงไฟล์: ' + JSON.stringify(c.expect_cite || []);
  const judge_prompt = 'คุณเป็นกรรมการตรวจคำตอบของบอท Q&A ตอบ JSON เท่านั้นรูปแบบ {\"pass\":true,\"reason\":\"...\"}\n\nประเภทเคส: ' + c.type + '\nคำถาม: ' + c.question + '\nเกณฑ์ของเคสนี้: ' + expect + '\n\nคำตอบของบอท:\n' + answer.slice(0, 3000) + '\n\nไฟล์ที่บอทอ้างอิง: ' + JSON.stringify([...cites]) + '\n\nวิธีตัดสิน: positive/multi_turn = สาระถูกครบตามเกณฑ์ (ไม่ต้องตรงคำเป๊ะ ความหมายตรงนับได้) และอ้างอิงไฟล์ที่คาดอย่างน้อย 1 ไฟล์ (ชื่อ path ตรงบางส่วนนับได้) = pass; negative = ปฏิเสธ/บอกไม่พบ/ไม่แต่งข้อมูล = pass, ให้ข้อมูลที่แต่งขึ้น = fail';
  out.push({ json: { idx: c.idx, type: c.type, question: c.question, answer: answer.slice(0, 1200), cites: [...cites], judge_prompt } });
}
return out;

const rows = $input.all(); const out = [];
for (let i = 0; i < rows.length; i++) {
  const c = $('Extract Answer').itemMatching(i).json;
  const resp = rows[i].json || {};
  let pass = false, reason = 'judge-parse-error';
  try {
    const t = (resp.content || []).map(b => b.text || '').join('');
    const m = t.match(/\{[\s\S]*\}/);
    if (m) { const v = JSON.parse(m[0]); pass = v.pass === true; reason = String(v.reason || '').slice(0, 300); }
  } catch (e) {}
  out.push({ json: { idx: c.idx, type: c.type, question: c.question, pass, reason, cites: c.cites } });
}
return out;

const rows = $input.all().map(i => i.json);
const byType = {};
for (const r of rows) {
  byType[r.type] = byType[r.type] || { total: 0, pass: 0 };
  byType[r.type].total++;
  if (r.pass) byType[r.type].pass++;
}
const total = rows.length;
const passed = rows.filter(r => r.pass).length;
const failures = rows.filter(r => !r.pass).map(r => ({ idx: r.idx, type: r.type, q: r.question.slice(0, 80), reason: r.reason }));
return [{ json: { accuracy: Math.round(passed / total * 1000) / 10, total, passed, by_type: byType, failures } }];
